CREATE OR REPLACE FUNCTION fpb_get_loan_type_ref ( as_loan_type char ) RETURNS varchar AS $body$
DECLARE

ls_des sc_lon_m_rule.ref_contract_no%type;

BEGIN
   SELECT sc_lon_m_rule.ref_contract_no
   INTO STRICT  ls_des
   FROM sc_lon_m_rule
   WHERE sc_lon_m_rule.loan_type = as_loan_type;
   if coalesce(ls_des::text, '') = '' then ls_des := as_loan_type;end if;
  RETURN ls_des;
END;
$body$
